// Example: NeoPixel Rainbow Chase
// Cycle rainbow colors on a WS2812 strip on pin 6.
// Uses external 5V power supply for the LEDs.

#include <Adafruit_NeoPixel.h>

#define PIN 6
#define NUM_LEDS 8

Adafruit_NeoPixel strip(NUM_LEDS, PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  strip.begin();
  strip.setBrightness(50);
  strip.show();
}

void loop() {
  for (int i = 0; i < NUM_LEDS; i++) {
    int hue = (i * 65536 / NUM_LEDS) + (millis() * 10);
    strip.setPixelColor(i, strip.gamma32(strip.ColorHSV(hue)));
  }
  strip.show();
  delay(20);
}
